1	"use client";
2	
3	import { useState } from "react";
4	import { useRouter } from "next/navigation";
5	import { useAuth } from "@/lib/auth-context";
6	import { Button } from "@/components/ui/button";
7	import { Input } from "@/components/ui/input";
8	import { useToast } from "@/components/ui/toast";
9	
10	export default function LoginPage() {
11	  const router = useRouter();
12	  const { login, loginAsDemo } = useAuth();
13	  const { toast } = useToast();
14	  const [email, setEmail] = useState("");
15	  const [password, setPassword] = useState("");
16	  const [error, setError] = useState<string | null>(null);
17	  const [loading, setLoading] = useState(false);
18	
19	  const handleSubmit = async (e: React.FormEvent) => {
20	    e.preventDefault();
21	    setError(null);
22	    if (!email.trim() || !password.trim()) {
23	      setError("请输入邮箱和密码");
24	      return;
25	    }
26	    setLoading(true);
27	    try {
28	      await login(email, password);
29	      router.push("/home");
30	    } catch (err) {
31	      const message =
32	        err instanceof Error ? err.message : "登录失败，请检查邮箱和密码";
33	      setError(message);
34	      toast({ title: "登录失败", description: message, variant: "destructive" });
35	    } finally {
36	      setLoading(false);
37	    }
38	  };
39	
40	  return (
41	    <div className="flex flex-1 items-center justify-center px-4">
42	      <div className="w-full max-w-md space-y-6">
43	        <div className="text-center">
44	          <h1 className="text-2xl font-bold">IT 资产管理系统</h1>
45	          <p className="mt-1 text-sm text-muted-foreground">请登录以继续</p>
46	        </div>
47	
48	        <form onSubmit={handleSubmit} className="space-y-4">
49	          <div className="space-y-2">
50	            <label htmlFor="email" className="text-sm font-medium">
51	              邮箱
52	            </label>
53	            <Input
54	              id="email"
55	              type="email"
56	              value={email}
57	              onChange={(e) => setEmail(e.target.value)}
58	              placeholder="name@example.com"
59	              autoComplete="email"
60	            />
61	          </div>
62	
63	          <div className="space-y-2">
64	            <label htmlFor="password" className="text-sm font-medium">
65	              密码
66	            </label>
67	            <Input
68	              id="password"
69	              type="password"
70	              value={password}
71	              onChange={(e) => setPassword(e.target.value)}
72	              placeholder="••••••••"
73	              autoComplete="current-password"
74	            />
75	          </div>
76	
77	          {error !== null && (
78	            <div className="rounded-lg bg-destructive/10 px-3 py-2 text-sm text-destructive">
79	              {error}
80	            </div>
81	          )}
82	
83	          <Button type="submit" disabled={loading} className="w-full">
84	            {loading ? "登录中..." : "登录"}
85	          </Button>
86	        </form>
87	
88	        <div className="relative my-6">
89	          <div className="absolute inset-0 flex items-center">
90	            <div className="w-full border-t" />
91	          </div>
92	          <div className="relative flex justify-center text-xs uppercase">
93	            <span className="bg-background px-2 text-muted-foreground">或</span>
94	          </div>
95	        </div>
96	
97	        <div className="grid grid-cols-2 gap-2">
98	          <Button
99	            variant="outline"
100	            onClick={() => { loginAsDemo("EMPLOYEE"); router.push("/home"); }}
101	          >
102	            员工演示
103	          </Button>
104	          <Button
105	            variant="outline"
106	            onClick={() => { loginAsDemo("MANAGER"); router.push("/home"); }}
107	          >
108	            主管演示
109	          </Button>
110	          <Button
111	            variant="outline"
112	            onClick={() => { loginAsDemo("IT_ADMIN"); router.push("/home"); }}
113	          >
114	            IT 演示
115	          </Button>
116	          <Button
117	            variant="outline"
118	            onClick={() => { loginAsDemo("EXECUTIVE"); router.push("/home"); }}
119	          >
120	            高管演示
121	          </Button>
122	        </div>
123	      </div>
124	    </div>
125	  );
126	}
