135	        <Link href="/my-assets">
136	          <Button variant="outline">我的资产</Button>
137	        </Link>
138	        <Link href="/apply">
139	          <Button variant="outline">申领设备</Button>
140	        </Link>
141	        <Link href="/tickets">
142	          <Button variant="outline">我的工单</Button>
143	        </Link>
144	        <Link href="/chat">
145	          <Button variant="outline">AI 助手</Button>
146	        </Link>
147	        {user.role === "MANAGER" && (
148	          <Link href="/approvals">
149	            <Button variant="outline">待审批</Button>
150	          </Link>
151	        )}
152	        {user.role === "IT_ADMIN" && (
153	          <Link href="/it/home">
154	            <Button variant="outline">IT 管理</Button>
155	          </Link>
156	        )}
157	        {user.role === "EXECUTIVE" && (
158	          <Link href="/exec/dashboard">
159	            <Button variant="outline">数据看板</Button>
160	          </Link>
161	        )}
162	      </div>
163	
164	      {/* Recent Tickets */}
165	      <div>
166	        <div className="flex items-center justify-between mb-3">
167	          <h2 className="text-lg font-semibold">最近工单</h2>
168	          <Link href="/tickets" className="text-sm text-primary underline-offset-4 hover:underline">
169	            查看全部
170	          </Link>
171	        </div>
172	        {tickets.length === 0 ? (
173	          <EmptyState icon={Inbox} title="暂无工单" />
