30	export default function MyAssetsPage() {
31	  const { user } = useAuth();
32	  const [assets, setAssets] = useState<AssetItem[]>([]);
33	  const [page, setPage] = useState(1);
34	  const [totalPages, setTotalPages] = useState(1);
35	  const [loading, setLoading] = useState(true);
36	  const [error, setError] = useState<string | null>(null);
37	
38	  const fetchAssets = async (p: number) => {
39	    setLoading(true);
40	    setError(null);
41	    try {
42	      const res = await apiFetch<PaginatedResponse<AssetItem>>("/api/assets/mine", {
43	        params: { page: p, pageSize: 20 },
44	      });
45	      setAssets(res.data);
46	      setTotalPages(res.pagination.totalPages);
47	      setPage(res.pagination.page);
48	    } catch (err) {
49	      setError(err instanceof Error ? err.message : "加载失败");
50	    } finally {
51	      setLoading(false);
52	    }
53	  };
54	
55	  useEffect(() => {
56	    fetchAssets(1);
57	  }, []);
58	
59	  const warrantyStatus = (expiry: string) => {
60	    const now = new Date();
61	    const exp = new Date(expiry);
62	    const daysLeft = Math.ceil((exp.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
63	    if (daysLeft < 0) return "已过保";
64	    if (daysLeft < 30) return `${daysLeft}天后到期`;
65	    return `${daysLeft}天`;
66	  };
67	
68	  if (loading) {
69	    return (
70	      <div className="flex flex-1 items-center justify-center p-4">
71	        <div className="w-full max-w-4xl space-y-4">
72	          <Skeleton className="h-8 w-32" />
73	          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
74	            {[1, 2, 3, 4].map((i) => (
75	              <Skeleton key={i} className="h-40 rounded-lg" />
76	            ))}
77	          </div>
78	        </div>
79	      </div>
80	    );
81	  }
82	
83	  if (error !== null) {
84	    return (
85	      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
86	        <p className="text-destructive">{error}</p>
87	        <Button onClick={() => fetchAssets(1)}>重试</Button>
88	      </div>
89	    );
90	  }
91	
92	  return (
93	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
94	      <PageHeader title="我的资产" />
95	
96	      {assets.length === 0 ? (
97	        <EmptyState icon={Inbox} title="暂无资产" action={{ href: "/apply", label: "申领设备" }} />
98	      ) : (
99	        <>
100	          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
101	            {assets.map((asset) => (
102	              <div key={asset.id} className="rounded-lg border p-4 space-y-2">
103	                <div className="flex items-start justify-between">
104	                  <div>
105	                    <p className="font-medium">{asset.model?.modelName ?? "未知型号"}</p>
106	                    <p className="text-sm text-muted-foreground">{asset.model?.brandName}</p>
107	                  </div>
108	                  <AssetStatusBadge status={asset.status as AssetInstanceStatus} />
109	                </div>
110	                <p className="text-xs text-muted-foreground">
111	                  分类: {asset.model?.category ?? "未知"}
112	                </p>
113	                <p className="text-xs text-muted-foreground">
114	                  保修: {warrantyStatus(asset.warrantyExpiry)}
115	                </p>
116	              </div>
117	            ))}
118	          </div>
119	
120	          {totalPages > 1 && (
121	            <div className="flex items-center justify-center gap-2">
122	              <Button variant="outline" disabled={page <= 1} onClick={() => fetchAssets(page - 1)}>
123	                上一页
124	              </Button>
125	              <span className="text-sm text-muted-foreground">
126	                {page} / {totalPages}
127	              </span>
128	              <Button variant="outline" disabled={page >= totalPages} onClick={() => fetchAssets(page + 1)}>
129	                下一页
130	              </Button>
131	            </div>
132	          )}
133	        </>
134	      )}
135	    </div>
136	  );
137	}
