81	
82	  if (loading) {
83	    return (
84	      <div className="flex flex-1 items-center justify-center p-4">
85	        <div className="w-full max-w-4xl space-y-4">
86	          <Skeleton className="h-8 w-32" />
87	          <div className="flex gap-2">
88	            {[1, 2, 3].map((i) => (
89	              <Skeleton key={i} className="h-9 w-28" />
90	            ))}
91	          </div>
92	          {[1, 2, 3, 4, 5].map((i) => (
93	            <Skeleton key={i} className="h-16 rounded-lg" />
94	          ))}
95	        </div>
96	      </div>
97	    );
98	  }
99	
100	  if (error !== null) {
101	    return (
102	      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
103	        <p className="text-destructive">{error}</p>
104	        <Button onClick={() => fetchTickets(1)}>重试</Button>
105	      </div>
106	    );
107	  }
108	
109	  return (
110	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
