113	      {/* Filters */}
114	      <div className="flex flex-wrap gap-2">
115	        <Select value={typeFilter} onValueChange={(value) => { setTypeFilter(value); setPage(1); }}>
116	          <SelectTrigger>
117	            <SelectValue placeholder="全部类型" />
118	          </SelectTrigger>
119	          <SelectContent>
120	            {TYPE_OPTIONS.map((o) => (
121	              <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
122	            ))}
123	          </SelectContent>
124	        </Select>
125	        <Select value={statusFilter} onValueChange={(value) => { setStatusFilter(value); setPage(1); }}>
126	          <SelectTrigger>
127	            <SelectValue placeholder="全部状态" />
128	          </SelectTrigger>
129	          <SelectContent>
130	            {STATUS_OPTIONS.map((o) => (
131	              <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
132	            ))}
133	          </SelectContent>
134	        </Select>
135	      </div>
136	
137	      {tickets.length === 0 ? (
138	        <EmptyState icon={Inbox} title="暂无工单" action={{ href: "/apply", label: "申领设备" }} />
139	      ) : (
140	        <>
141	          <div className="space-y-2">
